import React, { useState, useEffect } from 'react';
import { Card, Button, Modal, Form, Row, Col } from 'react-bootstrap';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import { FaShip } from 'react-icons/fa';

// ... (keep your existing imports)

// Pricing configuration (adjust as needed)
const PRICING = {
  'Sunday': 2500,
  'Monday': 2000,
  'Tuesday': 2000,
  'Wednesday': 2200,
  'Thursday': 2200,
  'Friday': 3000,
  'Saturday': 3500
};

function BookingCardView() {
  // ... (keep existing state declarations)

  const calculatePrice = (seats, day) => {
    const basePrice = PRICING[day] || 2000; // Default price if day not found
    return seats * basePrice;
  };

  const handleDayChange = (day) => {
    setFormData(prev => {
      const seats = prev.seats || 1;
      return {
        ...prev,
        day,
        price: calculatePrice(seats, day)
      };
    });
  };

  const handleSeatsChange = (seats) => {
    setFormData(prev => {
      const day = prev.day || days[0]; // Default to first day if none selected
      return {
        ...prev,
        seats,
        price: calculatePrice(seats, day)
      };
    });
  };

  const handleBooking = async () => {
    const { userName, seats, day, date, price } = formData;

    if (!userName || !seats || !day || !date || !price) {
      toast.warning('Please fill all booking details.');
      return;
    }

    try {
      const bookingData = {
        userName,
        seats,
        day,
        date,
        price,
        boatId: selectedBoat.id,
        boatName: selectedBoat.name
      };

      const response = await fetch('http://127.0.0.1:5000/user_booking', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(bookingData)
      });

      if (!response.ok) {
        throw new Error('Booking failed');
      }

      const result = await response.json();
      toast.success(`Booking confirmed! Reference: ${result.bookingId}`);
      handleClose();
    } catch (error) {
      toast.error(`Booking failed: ${error.message}`);
    }
  };

  // ... (keep existing render code until the Modal)

  return (
    // ... (keep existing JSX until the Modal)

    <Modal show={showModal} onHide={handleClose} centered>
      <Modal.Header closeButton>
        <Modal.Title>Book {selectedBoat?.name}</Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <Form>
          {/* User Name Field */}
          <Form.Group className="mb-3">
            <Form.Label>User Name</Form.Label>
            <Form.Control
              type="text"
              name="userName"
              value={formData.userName}
              onChange={(e) => handleChange(e)}
              placeholder="Enter your name"
              required
            />
          </Form.Group>

          {/* Number of Seats */}
          <Form.Group className="mb-3">
            <Form.Label>Number of Seats</Form.Label>
            <Form.Control
              type="number"
              name="seats"
              value={formData.seats}
              onChange={(e) => handleSeatsChange(e.target.value)}
              placeholder="e.g., 2"
              min="1"
              max={selectedBoat?.seatCount}
              required
            />
          </Form.Group>

          {/* Day Selection */}
          <Form.Group className="mb-3">
            <Form.Label>Day</Form.Label>
            <div>
              {days.map((day, idx) => (
                <Form.Check
                  key={idx}
                  inline
                  label={`${day} (₹${PRICING[day]})`}
                  name="day"
                  type="radio"
                  value={day}
                  checked={formData.day === day}
                  onChange={() => handleDayChange(day)}
                  required
                />
              ))}
            </div>
          </Form.Group>

          {/* Date Selection */}
          <Form.Group className="mb-3">
            <Form.Label>Date</Form.Label>
            <Form.Control
              type="date"
              name="date"
              value={formData.date}
              onChange={(e) => handleChange(e)}
              min={new Date().toISOString().split('T')[0]} // Today's date
              required
            />
          </Form.Group>

          {/* Price Display (read-only) */}
          <Form.Group className="mb-3">
            <Form.Label>Total Price (in ₹)</Form.Label>
            <Form.Control
              type="text"
              name="price"
              value={formData.price || ''}
              readOnly
              className="fw-bold"
            />
            <Form.Text className="text-muted">
              Price calculated automatically based on day and seats
            </Form.Text>
          </Form.Group>
        </Form>
      </Modal.Body>
      <Modal.Footer>
        <Button variant="danger" onClick={handleClose}>
          Cancel
        </Button>
        <Button variant="primary" onClick={handleBooking}>
          Confirm Booking
        </Button>
      </Modal.Footer>
    </Modal>
  );
}

export default BookingCardView;
